function generateDashboard(data) {
  const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  const now = new Date();
  const today = now.toISOString().slice(0, 10);
  const timeStr = now.toLocaleString('zh-CN');

  // 活跃阶段列表（9阶段）
  const stageOrder = ['需求探索', '报价已发', '谈判中', '待付款', '待发货', '已发货/在途', '已签收', '售后', '待返单'];
  // 终态
  const terminalStages = ['搁置', '未成交'];
  const gradeOrder = ['S', 'A', 'B', 'C', 'D'];

  // 按阶段分组
  const byStage = {};
  for (const s of stageOrder) byStage[s] = [];
  for (const t of terminalStages) byStage[t] = [];
  for (const e of data) {
    const s = e.stage || '需求探索';
    if (byStage[s]) byStage[s].push(e);
    else {
      if (!byStage['需求探索']) byStage['需求探索'] = [];
      byStage['需求探索'].push(e);
    }
  }

  // 合并 s2 数据（获取 lastCustomerMsgDays 等字段）
  const s2Path2 = path.join(__dirname, '..', 'data', 's2_ai_input.json');
  let mergedData = data;
  if (fs.existsSync(s2Path2)) {
    try {
      const s2Data = JSON.parse(fs.readFileSync(s2Path2, 'utf8'));
      const s2Map = new Map();
      for (const s of s2Data) s2Map.set(s.cid || s.name, s);
      mergedData = data.map(d => {
        const s2 = s2Map.get(d.cid) || s2Map.get(d.name);
        return s2 ? { ...s2, ...d, lastCustomerMsgDays: s2.lastCustomerMsgDays, countryCN: s2.country ? countryCN(s2.country) : d.countryCN || '' } : d;
      });
    } catch (e) {}
  }

  // 用合并后的数据重建 byStage
  const byStage2 = {};
  for (const s of stageOrder) byStage2[s] = [];
  for (const t of terminalStages) byStage2[t] = [];
  for (const e of mergedData) {
    const s = e.stage || '需求探索';
    if (byStage2[s]) byStage2[s].push(e);
    else { if (!byStage2['需求探索']) byStage2['需求探索'] = []; byStage2['需求探索'].push(e); }
  }

  const silenceTiers = [
    { label: '近期活跃 <3天', color: '#27ae60', maxD: 3 },
    { label: '近期活跃 3-7天', color: '#27ae60', maxD: 7, minD: 3 },
    { label: '短期静默 7-14天', color: '#3498db', maxD: 14, minD: 7 },
    { label: '中期静默 14-30天', color: '#f39c12', maxD: 30, minD: 14 },
    { label: '长期静默 30-90天', color: '#e67e22', maxD: 90, minD: 30 },
    { label: '沉淀 90天+', color: '#c0392b', maxD: 99999, minD: 90 },
  ];
  const silenceGroups = {};
  for (const tier of silenceTiers) silenceGroups[tier.label] = [];
  for (const e of mergedData) {
    const d = (e.lastCustomerMsgDays == null || e.lastCustomerMsgDays === '-') ? 9999 : e.lastCustomerMsgDays;
    if (typeof d !== 'number') { silenceGroups['沉淀 90天+'].push(e); continue; }
    for (const tier of silenceTiers) {
      if (d < tier.maxD && (tier.minD === undefined || d >= tier.minD)) {
        silenceGroups[tier.label].push(e); break;
      }
    }
  }

  // 静默风险分级 HTML（可折叠）
  const silenceHtml = silenceTiers.map(tier => {
    const items = silenceGroups[tier.label] || [];
    if (items.length === 0) return '';
    const sorted = items.sort((a, b) => {
      const da = typeof a.lastCustomerMsgDays === 'number' ? a.lastCustomerMsgDays : 9999;
      const db = typeof b.lastCustomerMsgDays === 'number' ? b.lastCustomerMsgDays : 9999;
      return da - db;
    });
    const itemsHtml = sorted.map(e => {
      const d = typeof e.lastCustomerMsgDays === 'number' ? e.lastCustomerMsgDays : '?';
      const g = e.grade || '?';
      return '<div style="display:flex;justify-content:space-between;padding:2px 0;font-size:11px;"><span>' + esc(e.name) + ' <span style="color:var(--text-secondary);">' + esc(e.countryCN || e.country || '??') + ' · ' + g + '级</span></span><span>' + d + '天</span></div>';
    }).join('');
    const rgba = tier.color === '#27ae60' ? '39,174,96' : tier.color === '#3498db' ? '52,152,219' : tier.color === '#f39c12' ? '243,156,18' : tier.color === '#e67e22' ? '230,126,34' : '192,57,43';
    return '<div><div onclick="var d=this.nextElementSibling;d.style.display=d.style.display===\'block\'?\'none\':\'block\'" style="display:flex;justify-content:space-between;align-items:center;padding:10px 14px;border-bottom:1px solid var(--border);cursor:pointer;">' +
      '<span>● <strong style="color:' + tier.color + ';">' + tier.label + '</strong></span>' +
