'    :root { --bg-primary: #1d1d1f; --bg-secondary: #2d2d2f; --bg-tertiary: #3d3d3f;\n' +
'      --border: #424245; --text-primary: #f5f5f7; --text-secondary: #86868b;\n' +
'      --text-tertiary: #636366; --accent: #0a84ff; }\n' +
'  }\n' +
'  * { box-sizing: border-box; margin: 0; padding: 0; }\n' +
