function extractTimelineMeta(msgs) {
  let firstCustDate = null, lastCustDate = null, firstOurDate = null, lastOurDate = null;
  let custMsgs7d = 0, custMsgs30d = 0;
  const NOW = Date.now();
  const DAY = 86400000;
  for (const m of msgs) {
    const msg = m.message || m;
    const uid = msg.sender && msg.sender.uid || '';
    const date = msg.createAt;
    if (!date || isSys(msg.content)) continue;
    const ts = new Date(date).getTime();
