      if (!firstOurDate || date < firstOurDate) firstOurDate = date;
      if (!lastOurDate || date > lastOurDate) lastOurDate = date;
    } else if (uid) {
      if (!firstCustDate || date < firstCustDate) firstCustDate = date;
      if (!lastCustDate || date > lastCustDate) lastCustDate = date;
      if ((NOW - ts) / DAY <= 7) custMsgs7d++;
      if ((NOW - ts) / DAY <= 30) custMsgs30d++;
    }
  }
  return {
    firstCustDate: firstCustDate ? new Date(firstCustDate).toISOString().slice(0, 10) : null,
    lastCustDate: lastCustDate ? new Date(lastCustDate).toISOString().slice(0, 10) : null,
    firstOurDate: firstOurDate ? new Date(firstOurDate).toISOString().slice(0, 10) : null,
    lastOurDate: lastOurDate ? new Date(lastOurDate).toISOString().slice(0, 10) : null,
    custMsgs7d,
    custMsgs30d,
  };
}

