  generateDashboard(s3Data);
  process.exit(0);
}

// 检查是否有 AI 判定结果
const s3Path = path.join(__dirname, '..', 'data', 's3_ai_judgments.json');
const s3Exists = fs.existsSync(s3Path);
if (s3Exists) {
  const s3Data = JSON.parse(fs.readFileSync(s3Path, 'utf8'));
