  console.log('运行 AI 判定工作流后再执行: node scripts/enhanced_classify.js --dashboard-only');
}

function generateDashboard(data) {
  const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  const now = new Date();
  const today = now.toISOString().slice(0, 10);
  const timeStr = now.toLocaleString('zh-CN');

  // 活跃阶段列表（9阶段）
  const stageOrder = ['需求探索', '报价已发', '谈判中', '待付款', '待发货', '已发货/在途', '已签收', '售后', '待返单'];
  // 终态
  const terminalStages = ['搁置', '未成交'];
  const gradeOrder = ['S', 'A', 'B', 'C', 'D'];

  // 按阶段分组
  const byStage = {};
  for (const s of stageOrder) byStage[s] = [];
  for (const t of terminalStages) byStage[t] = [];
  for (const e of data) {
    const s = e.stage || '需求探索';
    if (byStage[s]) byStage[s].push(e);
    else {
      if (!byStage['需求探索']) byStage['需求探索'] = [];
      byStage['需求探索'].push(e);
    }
  }

  // 合并 s2 数据（获取 lastCustomerMsgDays 等字段）
  const s2Path2 = path.join(__dirname, '..', 'data', 's2_ai_input.json');
  let mergedData = data;
  if (fs.existsSync(s2Path2)) {
    try {
      const s2Data = JSON.parse(fs.readFileSync(s2Path2, 'utf8'));
      const s2Map = new Map();
      for (const s of s2Data) s2Map.set(s.cid || s.name, s);
      mergedData = data.map(d => {
        const s2 = s2Map.get(d.cid) || s2Map.get(d.name);
        return s2 ? { ...s2, ...d, lastCustomerMsgDays: s2.lastCustomerMsgDays, countryCN: s2.country ? countryCN(s2.country) : d.countryCN || '' } : d;
      });
    } catch (e) {}
  }

  // 用合并后的数据重建 byStage
  const byStage2 = {};
  for (const s of stageOrder) byStage2[s] = [];
  for (const t of terminalStages) byStage2[t] = [];
  for (const e of mergedData) {
    const s = e.stage || '需求探索';
    if (byStage2[s]) byStage2[s].push(e);
    else { if (!byStage2['需求探索']) byStage2['需求探索'] = []; byStage2['需求探索'].push(e); }
  }

  const silenceTiers = [
    { label: '近期活跃 <3天', color: '#27ae60', maxD: 3 },
    { label: '近期活跃 3-7天', color: '#27ae60', maxD: 7, minD: 3 },
    { label: '短期静默 7-14天', color: '#3498db', maxD: 14, minD: 7 },
    { label: '中期静默 14-30天', color: '#f39c12', maxD: 30, minD: 14 },
    { label: '长期静默 30-90天', color: '#e67e22', maxD: 90, minD: 30 },
    { label: '沉淀 90天+', color: '#c0392b', maxD: 99999, minD: 90 },
  ];
  const silenceGroups = {};
  for (const tier of silenceTiers) silenceGroups[tier.label] = [];
  for (const e of mergedData) {
    const d = (e.lastCustomerMsgDays == null || e.lastCustomerMsgDays === '-') ? 9999 : e.lastCustomerMsgDays;
    if (typeof d !== 'number') { silenceGroups['沉淀 90天+'].push(e); continue; }
    for (const tier of silenceTiers) {
      if (d < tier.maxD && (tier.minD === undefined || d >= tier.minD)) {
        silenceGroups[tier.label].push(e); break;
      }
    }
  }

  // 静默风险分级 HTML（可折叠）
  const silenceHtml = silenceTiers.map(tier => {
    const items = silenceGroups[tier.label] || [];
    if (items.length === 0) return '';
    const sorted = items.sort((a, b) => {
      const da = typeof a.lastCustomerMsgDays === 'number' ? a.lastCustomerMsgDays : 9999;
      const db = typeof b.lastCustomerMsgDays === 'number' ? b.lastCustomerMsgDays : 9999;
      return da - db;
    });
    const itemsHtml = sorted.map(e => {
      const d = typeof e.lastCustomerMsgDays === 'number' ? e.lastCustomerMsgDays : '?';
      const g = e.grade || '?';
      return '<div style="display:flex;justify-content:space-between;padding:2px 0;font-size:11px;"><span>' + esc(e.name) + ' <span style="color:var(--text-secondary);">' + esc(e.countryCN || e.country || '??') + ' · ' + g + '级</span></span><span>' + d + '天</span></div>';
    }).join('');
    const rgba = tier.color === '#27ae60' ? '39,174,96' : tier.color === '#3498db' ? '52,152,219' : tier.color === '#f39c12' ? '243,156,18' : tier.color === '#e67e22' ? '230,126,34' : '192,57,43';
    return '<div><div onclick="var d=this.nextElementSibling;d.style.display=d.style.display===\'block\'?\'none\':\'block\'" style="display:flex;justify-content:space-between;align-items:center;padding:10px 14px;border-bottom:1px solid var(--border);cursor:pointer;">' +
      '<span>● <strong style="color:' + tier.color + ';">' + tier.label + '</strong></span>' +
      '<strong style="font-size:16px;color:' + tier.color + ';">' + items.length + '</strong></div>' +
      '<div style="display:none;padding:8px 14px;background:rgba(' + rgba + ',0.08);border-bottom:1px solid var(--border);">' + itemsHtml + '</div></div>';
  }).filter(Boolean).join('');

  // KPI
  const total = mergedData.length;
  const active3d = mergedData.filter(e => typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays < 3).length;
  const silent90p = mergedData.filter(e => typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays >= 90).length;
  const directionToUs = mergedData.filter(e => e.direction === 'to_us').length;
  const needsAction = mergedData.filter(e => e.priority === 'now' || e.priority === 'soon').length;

  const kpiCards = [
    { num: total, label: '总客户', color: '#1a5276' },
    { num: active3d, label: '3天活跃', color: '#1a5276' },
    { num: silent90p, label: '超90天无互动', color: '#c0392b' },
    { num: directionToUs, label: '球在我方', color: '#e67e22' },
    { num: mergedData.filter(e => e.confidence === 'uncertain').length, label: '需确认', color: '#e74c3c' },
    { num: needsAction, label: '需行动', color: '#8e44ad' },
  ];

  // 双轴矩阵 (活跃阶段 × 质量)
  const matrixData = {};
  for (const s of stageOrder) { matrixData[s] = {}; for (const g of gradeOrder) matrixData[s][g] = []; }
  const terminalData = {};
  for (const t of terminalStages) terminalData[t] = [];
  for (const e of mergedData) {
    const s = e.stage || '需求探索';
    const g = e.grade || 'D';
    if (terminalStages.includes(s)) {
      terminalData[s].push(e);
    } else if (matrixData[s] && matrixData[s][g]) {
      matrixData[s][g].push(e);
    }
  }

  // 矩阵表格行
  const matrixRows = stageOrder.map(s => {
    const cells = gradeOrder.map(g => {
      const items = matrixData[s] ? (matrixData[s][g] || []) : [];
      const n = items.length;
      if (n === 0) return '<td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td>';
      let opacity = Math.min(0.5, 0.15 + n * 0.005);
      if (g === 'S') opacity = Math.min(0.5, 0.2 + n * 0.02);
      return '<td style="text-align:center;padding:6px 8px;border:1px solid var(--border);cursor:pointer;background:rgba(255,159,10,' + opacity + ');font-weight:600;" onclick="openModal(\'' + s + '\',\'' + g + '\')">' + n + '</td>';
    }).join('');
    return '<tr><td class="rl">' + s + '</td>' + cells + '</tr>';
  }).join('');

  // 终态池 HTML（可折叠）
  const terminalHtml = terminalStages.map(t => {
    const items = terminalData[t] || [];
    if (items.length === 0) return '';
    const icon = t === '搁置' ? '⏸' : '❌';
    const style = t === '未成交' ? 'border-color:#ff3b30;background:rgba(255,59,48,0.03);' : '';
    const tip = t === '搁置' ? '回访：直接跟进，"上次那个案子还在推进吗？"' : '回访：换产品/新切入点/等认证更新后重新激活';
    const sorted = items.sort((a, b) => {
      const da = typeof a.lastCustomerMsgDays === 'number' ? a.lastCustomerMsgDays : 9999;
      const db = typeof b.lastCustomerMsgDays === 'number' ? b.lastCustomerMsgDays : 9999;
      return da - db;
    });
    const itemsHtml = sorted.map(e => {
      const d = typeof e.lastCustomerMsgDays === 'number' ? e.lastCustomerMsgDays + '天' : '?';
      const grade = e.grade || '?';
      const reason = e.reason || e.actionHint || '';
      const conf = e.confidence === 'uncertain' ? ' ⚠️' : '';
      return '<div class="client-row"><span>' + esc(e.name) + conf + ' <span class="from-tag">' + esc(grade) + '级</span></span><span style="font-size:10px;color:var(--text-secondary);">' + esc(reason).substring(0, 40) + ' · ' + d + '</span></div>';
    }).join('');
    return '<div class="terminal-pool" style="' + style + '">' +
      '<div onclick="var d=this.nextElementSibling;d.style.display=d.style.display===\'block\'?\'none\':\'block\'" style="display:flex;justify-content:space-between;align-items:center;cursor:pointer;padding:4px 0;">' +
      '<h4 style="margin:0;">' + icon + ' ' + t + ' — ' + items.length + '人</h4>' +
      '<strong style="font-size:16px;color:var(--text-secondary);">' + items.length + '</strong></div>' +
      '<div style="display:none;max-height:400px;overflow-y:auto;">' + itemsHtml + '</div>' +
      '<div style="font-size:10px;color:var(--text-secondary);margin-top:6px;">' + tip + '</div></div>';
  }).filter(Boolean).join('');

  // 构建 JSON 数据（供弹窗用）
  function toEntry(e) {
    return {
      n: e.name, c: e.countryCN || e.country || '??',
      d: typeof e.lastCustomerMsgDays === 'number' ? e.lastCustomerMsgDays : 999,
      g: e.grade || '?',
      st: e.stage || '需求探索',
      ac: e.actionHint || '',
      pr: e.priority || 'idle',
      cf: e.confidence || 'certain',
      rs: e.reason || ''
    };
  }
  function kpiSort(arr) {
    const order = { now: 0, soon: 1, idle: 2 };
    return arr.sort((a, b) => {
      const pd = (order[a.pr] ?? 3) - (order[b.pr] ?? 3);
      if (pd !== 0) return pd;
      return a.d - b.d;
    });
  }

  const matrixJson = {};
  for (const s of stageOrder) {
    matrixJson[s] = {};
    for (const g of gradeOrder) {
      matrixJson[s][g] = kpiSort((matrixData[s][g] || []).map(toEntry));
    }
  }
  // 终态也加入 JSON
  for (const t of terminalStages) {
    matrixJson[t] = {};
    for (const g of gradeOrder) matrixJson[t][g] = [];
    for (const e of (terminalData[t] || [])) {
      const ge = e.grade || 'D';
      if (!matrixJson[t][ge]) matrixJson[t][ge] = [];
      matrixJson[t][ge].push(toEntry(e));
    }
  }

  const kpiJson = {
    "总客户": kpiSort(mergedData.map(toEntry)),
    "3天活跃": kpiSort(mergedData.filter(e => typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays < 3).map(toEntry)),
    "超90天无互动": kpiSort(mergedData.filter(e => typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays >= 90).map(toEntry)),
    "球在我方": kpiSort(mergedData.filter(e => e.direction === 'to_us').map(toEntry)),
    "需确认": kpiSort(mergedData.filter(e => e.confidence === 'uncertain').map(toEntry)),
    "需行动": kpiSort(mergedData.filter(e => e.priority === 'now' || e.priority === 'soon').map(toEntry))
  };

  const html = '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="utf-8">\n<title>OKKI 客户管道看板 — ' + today + '</title>\n' +
'<style>\n' +
'  :root { --bg-primary: #f5f5f7; --bg-secondary: #ffffff; --bg-tertiary: #e5e5e7; --border: #d1d1d6;\n' +
'    --text-primary: #1d1d1f; --text-secondary: #86868b; --text-tertiary: #aeaeb2;\n' +
'    --accent: #0071e3; --success: #34c759; --warning: #ff9f0a; --error: #ff3b30; }\n' +
'  @media (prefers-color-scheme: dark) {\n' +
'    :root { --bg-primary: #1d1d1f; --bg-secondary: #2d2d2f; --bg-tertiary: #3d3d3f;\n' +
'      --border: #424245; --text-primary: #f5f5f7; --text-secondary: #86868b;\n' +
'      --text-tertiary: #636366; --accent: #0a84ff; }\n' +
'  }\n' +
'  * { box-sizing: border-box; margin: 0; padding: 0; }\n' +
'  body { font-family: system-ui, -apple-system, BlinkMacSystemFont, sans-serif;\n' +
'    background: var(--bg-primary); color: var(--text-primary); line-height: 1.5;\n' +
'    padding: 20px 24px; max-width: 1500px; margin: 0 auto; }\n' +
'  h1 { font-size: 1.3rem; margin-bottom: 4px; }\n' +
'  .subtitle { color: var(--text-secondary); font-size: 0.85rem; margin-bottom: 20px; }\n' +
'  .kpi-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 10px; margin-bottom: 20px; }\n' +
'  .kpi { color: #fff; padding: 14px 12px; border-radius: 8px; text-align: center; cursor: pointer; transition: transform 0.15s; }\n' +
'  .kpi:hover { transform: scale(1.03); }\n' +
'  .kpi .num { font-size: 28px; font-weight: 700; }\n' +
'  .kpi .lbl { font-size: 11px; opacity: 0.9; }\n' +
'  .card { background: var(--bg-secondary); border: 1px solid var(--border); border-radius: 10px; overflow: hidden; margin-bottom: 16px; }\n' +
'  .card-hd { background: var(--bg-tertiary); padding: 10px 14px; font-weight: 600; font-size: 13px; border-bottom: 1px solid var(--border); }\n' +
'  .card-hd span { font-weight: normal; font-size: 11px; color: var(--text-secondary); }\n' +
'  table.mx { width: 100%; border-collapse: collapse; font-size: 11px; }\n' +
'  table.mx th { padding: 6px 4px; border: 1px solid var(--border); background: var(--bg-tertiary); font-weight: 600; font-size:10px; text-align:center; }\n' +
'  table.mx th.stage-col { width:76px; }\n' +
'  table.mx td { border: 1px solid var(--border); text-align: center; padding: 7px 3px; }\n' +
'  table.mx td.rl { font-weight: 600; font-size: 10px; background: var(--bg-tertiary); }\n' +
'  .terminal-row { display: flex; gap: 16px; padding: 14px; }\n' +
'  .terminal-pool { flex: 1; border: 1px solid var(--border); border-radius: 8px; padding: 12px 14px; }\n' +
'  .terminal-pool h4 { font-size: 12px; margin-bottom: 6px; }\n' +
'  .terminal-pool .from-tag { font-size: 10px; color: var(--text-secondary); background: var(--bg-tertiary); padding: 1px 6px; border-radius: 10px; margin-left: 4px; }\n' +
'  .terminal-pool .client-row { font-size: 11px; padding: 3px 0; display: flex; justify-content: space-between; border-bottom: 1px dotted var(--border); }\n' +
'  .terminal-pool .client-row:last-child { border-bottom: none; }\n' +
'  .footer { margin-top: 24px; padding: 14px; border-top: 1px solid var(--border); font-size: 11px; color: var(--text-secondary); text-align: center; }\n' +
'  .modal-overlay { display:none; position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(0,0,0,0.45); z-index:9999; justify-content:center; align-items:center; }\n' +
'  .modal-overlay.show { display:flex; }\n' +
'  .modal-box { background:var(--bg-secondary); border-radius:10px; width:750px; max-width:92vw; max-height:75vh; overflow-y:auto; box-shadow:0 8px 30px rgba(0,0,0,0.25); }\n' +
'  @media (prefers-color-scheme: dark) { .modal-box { box-shadow:0 8px 30px rgba(0,0,0,0.6); } }\n' +
'  .modal-hd { display:flex; justify-content:space-between; align-items:center; padding:14px 18px; border-bottom:1px solid var(--border); font-weight:600; font-size:15px; position:sticky; top:0; background:var(--bg-secondary); border-radius:10px 10px 0 0; z-index:1; }\n' +
'  .modal-close { cursor:pointer; font-size:20px; color:var(--text-secondary); line-height:1; padding:0 4px; border:none; background:none; }\n' +
'  .modal-close:hover { color:var(--text-primary); }\n' +
'  .modal-body { padding:14px 18px; }\n' +
'  .modal-body table { width:100%; border-collapse:collapse; font-size:12px; }\n' +
'  .modal-body th { padding:6px 8px; border:1px solid var(--border); background:var(--bg-tertiary); text-align:left; font-weight:600; }\n' +
'  .modal-body td { padding:6px 8px; border:1px solid var(--border); }\n' +
'</style>\n</head>\n<body>\n\n' +
'<h1>OKKI 客户管道看板</h1>\n' +
'<div class="subtitle">生成时间：' + timeStr + ' | AI 判定结果 | 数据源：s3_ai_judgments.json | 全覆盖 ' + total + ' 客户</div>\n\n' +
'<div class="kpi-grid">\n' +
  kpiCards.map(c => '<div class="kpi" style="background:' + c.color + ';" onclick="openKpiModal(\'' + c.label + '\')"><div class="num">' + c.num + '</div><div class="lbl">' + c.label + '</div></div>').join('\n') + '\n</div>\n\n' +
'<div class="card">\n  <div class="card-hd">客户双轴矩阵 <span>（8阶段活跃管线 × 质量等级）— 点击数字弹出客户名单</span></div>\n' +
'  <div style="overflow-x:auto;">\n    <table class="mx">\n      <tr><th class="stage-col">阶段 \\ 等级</th><th>S</th><th>A</th><th>B</th><th>C</th><th>D</th></tr>\n' +
'      ' + matrixRows + '\n    </table>\n  </div>\n' +
'  <div style="padding:6px 14px;font-size:10px;color:var(--text-secondary);">颜色越深=该格客户越多 | 点击数字弹出详情（AI判定结果 + 行动方向）</div>\n</div>\n\n' +
'<div class="card">\n  <div class="card-hd">终态池 <span>（从活跃阶段掉出，不出现在上方矩阵）</span></div>\n' +
'  <div class="terminal-row">' + (terminalHtml || '<div style="padding:14px;color:var(--text-secondary);font-size:12px;">暂无终态客户</div>') + '</div>\n</div>\n\n' +
'<div class="card">\n  <div class="card-hd">静默风险分级</div>\n  <div>' + silenceHtml + '</div>\n</div>\n\n' +
'<div class="footer">管道看板 — AI 判定生成 | 深度分析请新开对话 | 生成时间：' + timeStr + '</div>\n\n' +
'<div id="modal-overlay" class="modal-overlay" onclick="if(event.target===this)closeModal()">\n' +
'  <div class="modal-box"><div class="modal-hd"><span id="modal-title"></span><button class="modal-close" onclick="closeModal()">✕</button></div>\n' +
'    <div class="modal-body" id="modal-body"></div></div>\n</div>\n\n' +
'<script>\n' +
'window.MATRIX = ' + JSON.stringify(matrixJson) + ';\n' +
'window.KPI_DATA = ' + JSON.stringify(kpiJson) + ';\n' +
'function esc(s) { return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;"); }\n' +
'function gradeTag(g) {\n' +
'  var colors = {S:"#ff9f0a",A:"#0a84ff",B:"#636366",C:"#86868b",D:"#48484a"};\n' +
'  return \'<span style="background:\' + (colors[g]||\"#636366\") + \';color:\' + (g===\"S\"?\"#1d1d1f\":\"#fff\") + \';padding:1px 6px;border-radius:3px;font-size:10px;font-weight:600;margin-right:4px;\">\' + esc(g) + \'</span>\';\n' +
'}\n' +
'function prioIcon(p) {\n' +
'  var icons = {now:"🔴",soon:"🟡",idle:"⚪"};\n' +
'  return icons[p] || "";\n' +
'}\n' +
'function openKpiModal(key) {\n' +
'  var data = window.KPI_DATA[key] || [];\n' +
'  document.getElementById("modal-title").innerHTML = esc(key) + " — " + data.length + "人";\n' +
'  var rows = "";\n' +
'  for (var i = 0; i < data.length; i++) {\n' +
'    var c = data[i];\n' +
'    var confIcon = c.cf === "uncertain" ? " ⚠️" : "";\n' +
'    rows += "<tr><td>" + gradeTag(c.g) + "<strong>" + esc(c.n) + confIcon + "</strong></td><td style=\\"text-align:center;white-space:nowrap;font-size:11px;\\">" + esc(c.c) + " · " + (c.d === 999 ? "?" : c.d + "d") + "</td><td style=\\"font-size:12px;\\">" + esc(c.st) + "</td><td style=\\"color:var(--text-primary);font-weight:600;font-size:12px;\\">" + prioIcon(c.pr) + " " + esc(c.ac) + "</td></tr>";\n' +
'  }\n' +
'  document.getElementById("modal-body").innerHTML =\n' +
'    \'<div style="max-height:55vh;overflow-y:auto;"><table><tr><th style="width:140px;">客户</th><th style="text-align:center;width:100px;">国家 · 静默</th><th>阶段</th><th>行动方向</th></tr>\' + rows + \'</table></div>\' +\n' +
'    \'<div style="margin-top:8px;font-size:10px;color:var(--text-tertiary);">💡 🔴now=今天 🟡soon=本周 ⚪idle=暂不 | ⚠️=AI不确定需确认 | ESC/点击遮罩关闭</div>\';\n' +
'  document.getElementById("modal-overlay").classList.add("show");\n' +
