input.content:
// OKKI AI Classification v3.2 — 两段式：脚本提取 + AI语义判断
// 替换 v3.1 正则分类，38 张关键卡已 AI 逐卡判定阶段+置信度
const fs = require('fs');
const path = require('path');

const s2 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's2_ai_input.json'), 'utf8'));
const s3old = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's3_ai_judgments.json'), 'utf8'));
const ai38 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', '_ai_classification_v3_2_38cards.json'), 'utf8'));

// 构建 AI 判定映射
const aiMap = new Map();
for (const j of ai38.judgments) {
  aiMap.set(j.name, j);
}

// 加载旧的 s3 建立 cid 索引
const s3ByName = new Map();
for (const s of s3old) {
  s3ByName.set(s.name, s);
}

const results = [];
let aiCorrected = 0;
let regexKept = 0;
let newEntries = 0;

for (const c of s2) {
  const aiJudgment = aiMap.get(c.name);
  const oldS3 = s3ByName.get(c.name);

  let stage, priority, reason, confidence;

  if (aiJudgment) {
    // AI 已判定 → 直接使用
    stage = aiJudgment.new_stage;
    confidence = aiJudgment.confidence;
    reason = aiJudgment.reason;
    aiCorrected++;
  } else if (oldS3) {
    // 保持 v3.1 正则结果，但标低置信度
    stage = oldS3.stage;
    reason = oldS3.reason || '';
    confidence = 'regex';  // 标记为旧正则分类
    regexKept++;
  } else {
    // 新客户（s2有但s3没有）→ 基础判定
    const lastCust = c.lastCustomerMsgDays;
    if (lastCust === null || lastCust === undefined) {
      stage = '需求探索';
    } else if (lastCust > 90) {
      stage = '搁置';
    } else if (lastCust > 30) {
      stage = '搁置';
    } else {
      stage = '需求探索';
    }
    reason = '新条目，基础判定';
    confidence = 'low';
    newEntries++;
  }

  // 优先级判定
  const lastCust = c.lastCustomerMsgDays;
  if (stage === '搁置' || stage === '未成交') {
    priority = 'idle';
  } else if (lastCust !== null && lastCust !== undefined && lastCust <= 3) {
    priority = 'now';
  } else if (lastCust !== null && lastCust !== undefined && lastCust <= 14) {
    priority = 'soon';
  } else {
    priority = 'idle';
  }

  results.push({
    name: c.name,
    cid: c.cid,
    country: c.country,
    stage,
    grade: c.grade,
    priority,
    actionHint: reason,
    reason,
    confidence,
    actionPriority: priority,
    stageLabel: stage,
    actionStatus: priority === 'now' ? '紧急' : (priority === 'soon' ? '尽快处理' : '观察'),
    actionText: reason,
    _source: aiJudgment ? 'ai_v3.2' : (oldS3 ? 'regex_v3.1' : 'basic_v3.2'),
  });
}

// 统计
const stageDist = {};
const priorityDist = {};
const sourceDist = {};
for (const r of results) {
  stageDist[r.stage] = (stageDist[r.stage] || 0) + 1;
  priorityDist[r.priority] = (priorityDist[r.priority] || 0) + 1;
  sourceDist[r._source] = (sourceDist[r._source] || 0) + 1;
}

fs.writeFileSync(
  path.join(__dirname, '..', 'data', 's3_ai_judgments.json'),
  JSON.stringify(results, null, 2)
);

console.log('=== AI Classification v3.2 (两段式) ===');
console.log('总客户:', results.length);
console.log('AI判定(38张卡):', aiCorrected);
console.log('保持v3.1正则:', regexKept);
console.log('新条目(基础判定):', newEntries);
console.log('');
console.log('阶段分布:', JSON.stringify(stageDist));
console.log('优先级分布:', JSON.stringify(priorityDist));
console.log('数据源分布:', JSON.stringify(sourceDist));
console.log('');
console.log('已保存 data/s3_ai_judgments.json');

