  console.log(key + ' (' + names.length + '人):');
  for (const n of names) {
    const j = ai.judgments.find(x => x.name === n);
    console.log('  ' + n.padEnd(25) + (j.match ? ' ✓' : ' ✗') + '  ' + j.reason.substring(0, 60));
  }
  console.log('');
}

// 错误类型分析
console.log('--- 旧正则错误类型分析 ---');
const errorTypes = {
  '静默超30天未识别为搁置': [],
  '无订单却判待发货/待付款': [],
  '有订单结果被忽略': [],
  '浅互动误判为深阶段': [],
  '客户明确拒绝未识别': [],
};
for (const j of ai.judgments) {
  if (j.match) continue;
  const o = j.old_stage;
  const n = j.new_stage;
  if (n === '搁置' && o !== '搁置') {
    if (j.reason.includes('静默') || j.reason.includes('无回复')) 
      errorTypes['静默超30天未识别为搁置'].push(j.name);
  }
  if ((o === '待发货' || o === '待付款') && (n === '报价已发' || n === '需求探索' || n === '谈判中'))
    errorTypes['无订单却判待发货/待付款'].push(j.name);
  if ((n === '已签收' || n === '已发货/在途' || n === '待付款') && (o === '需求探索' || o === '谈判中'))
    errorTypes['有订单结果被忽略'].push(j.name);
  if ((n === '需求探索' || n === '报价已发') && o === '谈判中')
    errorTypes['浅互动误判为深阶段'].push(j.name);
  if (n === '未成交' && o !== '未成交')
    errorTypes['客户明确拒绝未识别'].push(j.name);
}
for (const [type, names] of Object.entries(errorTypes)) {
  if (names.length > 0) console.log(type + ': ' + names.length + '人');
}

console.log('');
console.log('旧正则准确: 1/38 = 2.6%');
console.log('旧正则错误: 37/38 = 97.4%');
console.log('唯一匹配: Inderpreet kaur (谈判中) — 因关键词密集+近期活跃，正则碰巧对了');
